def test_valid_signup(test_client):
    response = test_client.post('/register', json={
        'email': 'newuser@example.com',
        'password': 'NewStrongPass123!'
    })
    assert response.status_code == 201, "Should create a new user successfully."

def test_oauth_signup_google(test_client):
    response = test_client.post('/oauth/google', json={'token': 'fake-google-token'})
    assert response.status_code == 200, "Should register/login via Google OAuth."

def test_oauth_signup_github(test_client):
    response = test_client.post('/oauth/github', json={'token': 'fake-github-token'})
    assert response.status_code == 200, "Should register/login via GitHub OAuth."
